module deepbook_trader::market_order {
    use sui::tx_context::TxContext;
    use sui::object::{Self, UID};
    use sui::transfer;
    use sui::coin::{Self, Coin};
    use sui::balance::{Self, Balance};
    use deepbook::market::{Self, Market};
    use deepbook::order::{Self, Order};
    use deepbook::critbit::Slab;
    use deepbook::custodian::{Self, Custodian};
    use deepbook::utils;

    /// Proof that a trade was executed
    public struct TradeProof has key, store {
        id: UID,
        base_amount: u64,
        quote_amount: u64,
        is_buy: bool
    }

    /// Executes a market order on DeepBook
    public entry fun execute_market_order<BaseType, QuoteType>(
        market: &mut Market<BaseType, QuoteType>,
        custodian: &mut Custodian<BaseType, QuoteType>,
        base_coins: vector<Coin<BaseType>>,
        quote_coins: vector<Coin<QuoteType>>,
        is_buy: bool,
        quantity: u64,
        ctx: &mut TxContext
    ) {
        let base_balance = balance::zero<BaseType>();
        let quote_balance = balance::zero<QuoteType>();

        // Merge all input coins into balances
        while (!coin::is_empty(vector::borrow(&base_coins, 0))) {
            let coin = vector::pop_back(&mut base_coins);
            balance::join(&mut base_balance, coin::into_balance(coin));
        };

        while (!coin::is_empty(vector::borrow(&quote_coins, 0))) {
            let coin = vector::pop_back(&mut quote_coins);
            balance::join(&mut quote_balance, coin::into_balance(coin));
        };

        // Create order
        let order = if (is_buy) {
            order::new_market_buy(quantity, balance::into_coin(quote_balance))
        } else {
            order::new_market_sell(quantity, balance::into_coin(base_balance))
        };

        // Place order and get results
        let (base_coin, quote_coin, filled_quantity) = market::place_order(
            market,
            custodian,
            order,
            ctx
        );

        // Create trade proof
        let trade_proof = TradeProof {
            id: object::new(ctx),
            base_amount: if (is_buy) { filled_quantity } else { coin::value(&base_coin) },
            quote_amount: if (is_buy) { coin::value(&quote_coin) } else { filled_quantity },
            is_buy
        };

        // Transfer coins back to sender
        if (is_buy) {
            transfer::public_transfer(base_coin, utils::sender(ctx));
        } else {
            transfer::public_transfer(quote_coin, utils::sender(ctx));
        };

        // Transfer trade proof to sender
        transfer::public_transfer(trade_proof, utils::sender(ctx));
    }
}

