        abort 1337
    }

    #[test, expected_failure(abort_code = sui::kiosk_extension::EExtensionNotInstalled)]
    fun test_remove_not_installed() {
        let ctx = &mut test::ctx();
        let (mut kiosk, owner_cap) = test::get_kiosk(ctx);

