/// Set price deviation tolerance for a pool
/// tolerance is in 9 decimals where 1.0 = 1_000_000_000 (e.g., 100_000_000 = 0.1 = 10%)
/// Only Admin can set tolerance
/// Requires price to be initialized first via update_current_price
public fun set_price_tolerance<BaseAsset, QuoteAsset>(
    self: &mut MarginRegistry,
    _admin_cap: &MarginAdminCap,
    pool: &Pool<BaseAsset, QuoteAsset>,
    tolerance: u64,
    clock: &Clock,
) {
    assert!(tolerance >= margin_constants::min_price_tolerance(), EToleranceTooLow);
    assert!(tolerance <= margin_constants::max_price_tolerance(), EToleranceTooHigh);

    self.load_inner();
    let pool_id = pool.id();
    let key = CurrentPriceKey { pool_id };

    assert!(self.id.exists_with_type<CurrentPriceKey, CurrentPriceData>(key), EPriceNotInitialized);

    let price_data: &mut CurrentPriceData = self.id.borrow_mut(key);
    price_data.tolerance = tolerance;

    event::emit(PriceToleranceUpdated {
        pool_id,
        tolerance,
        timestamp: clock.timestamp_ms(),
    });
}

/// Set maximum price age in milliseconds for a pool
/// Only Admin can set max price age
/// Requires price to be initialized first via update_current_price
public fun set_max_price_age<BaseAsset, QuoteAsset>(
    self: &mut MarginRegistry,
    _admin_cap: &MarginAdminCap,
    pool: &Pool<BaseAsset, QuoteAsset>,
    max_age_ms: u64,
    clock: &Clock,
) {
    assert!(max_age_ms >= margin_constants::min_price_age_ms(), EMaxPriceAgeTooLow);
    assert!(max_age_ms <= margin_constants::max_price_age_ms(), EMaxPriceAgeTooHigh);

    self.load_inner();
    let pool_id = pool.id();
    let key = CurrentPriceKey { pool_id };

    assert!(self.id.exists_with_type<CurrentPriceKey, CurrentPriceData>(key), EPriceNotInitialized);

    let price_data: &mut CurrentPriceData = self.id.borrow_mut(key);
    price_data.max_price_age_ms = max_age_ms;

    event::emit(MaxPriceAgeUpdated {
        pool_id,
        max_age_ms,
        timestamp: clock.timestamp_ms(),
    });
}

/// Set the maximum lifetime (in ms) of margin limit orders for a pool.
/// User-supplied `expire_timestamp` on margin limit-order placements is
/// clamped to at most `now + max_order_ttl_ms`. Bounds margin orders'
/// exposure to stale-price exploitation if liquidity disappears after
/// placement.
/// Only Admin can set max order TTL.
public fun set_max_order_ttl<BaseAsset, QuoteAsset>(
    self: &mut MarginRegistry,
    _admin_cap: &MarginAdminCap,
    pool: &Pool<BaseAsset, QuoteAsset>,
    max_order_ttl_ms: u64,
    clock: &Clock,
) {
    self.load_inner();
    assert!(max_order_ttl_ms >= margin_constants::min_max_order_ttl_ms(), EInvalidOrderTtl);
    assert!(max_order_ttl_ms <= margin_constants::max_max_order_ttl_ms(), EInvalidOrderTtl);

    let pool_id = pool.id();
    let key = MaxOrderTtlKey(pool_id);

    if (self.id.exists_with_type<MaxOrderTtlKey, u64>(key)) {
        let stored: &mut u64 = self.id.borrow_mut(key);
        *stored = max_order_ttl_ms;
    } else {
        self.id.add(key, max_order_ttl_ms);
    };

    event::emit(MaxOrderTtlUpdated {
        pool_id,
        max_order_ttl_ms,
        timestamp: clock.timestamp_ms(),
    });
}

// === Public Helper Functions ===
/// Create a PoolConfig with margin pool IDs and risk parameters
/// Enable is false by default, must be enabled after registration
public fun new_pool_config<BaseAsset, QuoteAsset>(
    self: &MarginRegistry,
    min_withdraw_risk_ratio: u64,
    min_borrow_risk_ratio: u64,
    liquidation_risk_ratio: u64,
    target_liquidation_risk_ratio: u64,
    user_liquidation_reward: u64,
    pool_liquidation_reward: u64,
): PoolConfig {
    assert!(min_borrow_risk_ratio < min_withdraw_risk_ratio, EInvalidRiskParam);
    assert!(liquidation_risk_ratio < min_borrow_risk_ratio, EInvalidRiskParam);
    assert!(liquidation_risk_ratio < target_liquidation_risk_ratio, EInvalidRiskParam);
    assert!(liquidation_risk_ratio >= constants::float_scaling(), EInvalidRiskParam);
    assert!(user_liquidation_reward <= constants::float_scaling(), EInvalidRiskParam);
    assert!(pool_liquidation_reward <= constants::float_scaling(), EInvalidRiskParam);
    assert!(
        user_liquidation_reward + pool_liquidation_reward <= constants::float_scaling(),
        EInvalidRiskParam,
    );
    assert!(
        target_liquidation_risk_ratio >
        constants::float_scaling() + user_liquidation_reward + pool_liquidation_reward,
        EInvalidRiskParam,
    );

    PoolConfig {
        base_margin_pool_id: self.get_margin_pool_id<BaseAsset>(),
        quote_margin_pool_id: self.get_margin_pool_id<QuoteAsset>(),
        risk_ratios: RiskRatios {
            min_withdraw_risk_ratio,
            min_borrow_risk_ratio,
            liquidation_risk_ratio,
            target_liquidation_risk_ratio,
        },
        user_liquidation_reward,
        pool_liquidation_reward,
        enabled: false,
        extra_fields: vec_map::empty(),
    }
}

/// Create a PoolConfig with default risk parameters based on leverage
public fun new_pool_config_with_leverage<BaseAsset, QuoteAsset>(
    self: &MarginRegistry,
    leverage: u64,
): PoolConfig {
    self.load_inner();
    assert!(leverage > margin_constants::min_leverage(), EInvalidRiskParam);
    assert!(leverage <= margin_constants::max_leverage(), EInvalidRiskParam);

    let factor = math::div(constants::float_scaling(), leverage - constants::float_scaling());
    let risk_ratios = calculate_risk_ratios(factor);

    self.new_pool_config<BaseAsset, QuoteAsset>(
        risk_ratios.min_withdraw_risk_ratio,
        risk_ratios.min_borrow_risk_ratio,
        risk_ratios.liquidation_risk_ratio,
        risk_ratios.target_liquidation_risk_ratio,
        margin_constants::default_user_liquidation_reward(),
        margin_constants::default_pool_liquidation_reward(),
    )
}

