module deepbook_example::limit_order {
    use sui::balance_manager::BalanceManager;
    use sui::coin::{Coin, Self};
    use sui::tx_context::TxContext;
    use deepbook::pool::Pool;
    use deepbook::types::{OrderSide, OrderType};
    use deepbook::utils::price_to_tick;
    use deepbook::v3::deepbook::place_limit_order;

    public fun place_limit_order_with_balance_manager<BaseType, QuoteType>(
        pool: &mut Pool<BaseType, QuoteType>,
        balance_manager: &mut BalanceManager,
        side: u8,
        quantity: u64,
        price: u64,
        order_type: u8,
        client_order_id: u64,
        ctx: &mut TxContext
    ) {
        let (base_coin, quote_coin) = if (side == (OrderSide::Ask as u8)) {
            let base_coin = balance_manager.withdraw<BaseType>(quantity);
            (base_coin, coin::zero<QuoteType>())
        } else {
            let quote_value = quantity * price;
            let quote_coin = balance_manager.withdraw<QuoteType>(quote_value);
            (coin::zero<BaseType>(), quote_coin)
        };

        let tick = price_to_tick(price);

        place_limit_order(
            pool,
            base_coin,
            quote_coin,
            side,
            quantity,
            tick,
            order_type,
            client_order_id,
            ctx
        );
    }
}
