public fun place_limit_order<BaseCoin, QuoteCoin>(
    clob: &mut CLOB<BaseCoin, QuoteCoin>,
    balance_manager: &mut BalanceManager,
    price: u64,
    quantity: u64,
    is_buy: bool,
    ctx: &mut TxContext
) {
    let order_id = clob_v2::place_limit_order(clob, price, quantity, is_buy, ctx);
    let balance = if is_buy {
