        amount: u64,
        borrower: address,
    }

    /// Borrow DEEP tokens via flash loan
    public fun borrow_flash_loan(
        balances: &mut Balances,
        amount: u64,
        ctx: &mut TxContext
    ): FlashLoanReceipt {
        assert!(amount > 0, 0);
        let borrower = tx_context::sender(ctx);

        // Mint the borrowed amount
        balances::mint(balances, amount, ctx);

        // Create and return receipt
        FlashLoanReceipt {
            id: object::new(ctx),
            amount,
            borrower,
        }
    }

