        assert!(tx_context::sender(ctx) == borrower, 1);

        // Burn the repaid amount
        balances::burn(balances, amount, ctx);

        // Emit success event
        event::emit(FlashLoanEvent {
            amount,
            borrower,
            repaid: true,
        });

        // Destroy the receipt
        object::delete(id);
