/// Token Bucket rate limiter for controlling withdrawal rates.
/// Reference: https://github.com/code-423n4/2024-11-chainlink/blob/main/contracts/src/ccip/libraries/RateLimiter.sol
module deepbook_margin::rate_limiter;

use std::u128::min;
use sui::clock::Clock;

public struct RateLimiter has store {
    available: u64,
    last_updated_ms: u64,
    capacity: u64,
    refill_rate_per_ms: u64,
    enabled: bool,
}

// === Public-Package Functions ===

public(package) fun new(
    capacity: u64,
    refill_rate_per_ms: u64,
    enabled: bool,
    clock: &Clock,
): RateLimiter {
    RateLimiter {
        available: capacity,
        last_updated_ms: clock.timestamp_ms(),
        capacity,
        refill_rate_per_ms,
        enabled,
    }
}

public(package) fun check_and_record_withdrawal(
    self: &mut RateLimiter,
    amount: u64,
    clock: &Clock,
): bool {
    if (!self.enabled) return true;

    self.refill(clock);

    if (amount > self.available) {
        return false
    };

    self.available = self.available - amount;
    true
}

public(package) fun record_deposit(self: &mut RateLimiter, amount: u64) {
    self.available = min(self.available + amount, self.capacity);
}

