module deepbook_examples::market_order {
    use sui::tx_context::TxContext;
    use deepbook::order_book::{Self, OrderBook};
    use deepbook::custodian::{Self, Custodian};
    use deepbook::types::{Order, OrderType, Side};
    use deepbook::utils::{Self, TradeProof};
    use sui::coin::{Coin};
    use sui::balance::{Balance};
    use sui::transfer;
    use sui::object::{ID, UID};

    public fun execute_market_order<BaseAsset, QuoteAsset>(
        order_book: &mut OrderBook<BaseAsset, QuoteAsset>,
        custodian: &mut Custodian<BaseAsset, QuoteAsset>,
        side: Side,
        quantity: u64,
        quote_coin: Coin<QuoteAsset>,
        ctx: &mut TxContext
    ): (TradeProof<BaseAsset, QuoteAsset>, Coin<QuoteAsset>) {
        let order = Order {
            order_type: OrderType::Market,
            side,
            quantity,
            price: 0, // Market orders don't need price
            client_order_id: 0,
            expiration_timestamp: 0,
            sender: tx_context::sender(ctx),
        };

        let (trade_proof, remaining_quote_coin) = order_book::place_order(
            order_book,
            custodian,
            order,
            quote_coin,
            ctx
        );

        (trade_proof, remaining_quote_coin)
    }

    public entry fun create_and_execute_market_order<BaseAsset, QuoteAsset>(
        order_book: &mut OrderBook<BaseAsset, QuoteAsset>,
        custodian: &mut Custodian<BaseAsset, QuoteAsset>,
        side: Side,
        quantity: u64,
        quote_coin: Coin<QuoteAsset>,
        ctx: &mut TxContext
    ) {
        let (trade_proof, remaining_quote_coin) = execute_market_order(
            order_book,
            custodian,
            side,
            quantity,
            quote_coin,
            ctx
        );

        // Do something with the trade proof if needed
        utils::destroy_trade_proof(trade_proof);

        // Return remaining funds to sender
        if (coin::value(&remaining_quote_coin) > 0) {
            transfer::public_transfer(remaining_quote_coin, tx_context::sender(ctx));
        }
    }

    #[test_only]
    public fun test_market_order<BaseAsset, QuoteAsset>(
        order_book: &mut OrderBook<BaseAsset, QuoteAsset>,
        custodian: &mut Custodian<BaseAsset, QuoteAsset>,
        ctx: &mut TxContext
    ) {
        let quote_coin = coin::mint<QuoteAsset>(100000, ctx);
        create_and_execute_market_order(
            order_book,
            custodian,
            Side::Bid,
            1000,
            quote_coin,
            ctx
        );
    }
}
