module deepbook::limit_order {
    use sui::balance::BalanceManager;
    use sui::coin::Coin;
    use sui::transfer;
    use deepbook::deepbook_v3::{Self, DeepBookV3};
    use deepbook::types::{OrderSide, OrderType, OrderStatus};
    use sui::tx_context::TxContext;

    public fun place_limit_order<BaseCoin, QuoteCoin>(
        deepbook: &mut DeepBookV3<BaseCoin, QuoteCoin>,
        balance_manager: &mut BalanceManager,
        price: u64,
        quantity: u64,
        side: OrderSide,
        order_type: OrderType,
        clock: &Clock,
        ctx: &mut TxContext
    ) {
        // Validate order parameters
        assert!(price > 0, 0);
        assert!(quantity > 0, 1);

        // Get the appropriate coin balance based on order side
        let coin_to_use = if (side == OrderSide::Bid) {
            balance_manager.get_balance<QuoteCoin>(ctx)
        } else {
            balance_manager.get_balance<BaseCoin>(ctx)
        };

        // Calculate required amount
        let required_amount = if (side == OrderSide::Bid) {
            price * quantity
        } else {
            quantity
        };

        // Check sufficient balance
        assert!(coin_to_use.value() >= required_amount, 2);

        // Split the required amount from balance
        let order_coin = balance_manager.split_coin(&mut coin_to_use, required_amount);

        // Place the order on DeepBook
        let order_id = deepbook_v3::place_order(
            deepbook,
            side,
            order_type,
            price,
            quantity,
            order_coin,
            clock,
            ctx
        );

        // Emit event or handle order placement result
        // (implementation depends on your specific requirements)
    }

    public fun cancel_order<BaseCoin, QuoteCoin>(
        deepbook: &mut DeepBookV3<BaseCoin, QuoteCoin>,
        balance_manager: &mut BalanceManager,
        order_id: u64,
        ctx: &mut TxContext
    ) {
        let (status, refund_coin) = deepbook_v3::cancel_order(deepbook, order_id, ctx);

        // Handle the refund based on order status
        if (status == OrderStatus::Cancelled || status == OrderStatus::PartiallyFilled) {
            balance_manager.merge_coin(refund_coin);
        }
    }
}
