module deepbook::clob {
    use std::type_name::TypeName;

    use sui::balance::{Self, Balance};
    use sui::clock::{Self, Clock};
    use sui::coin::Coin;
    use sui::event;
    use sui::linked_table::{Self, LinkedTable};
    use sui::sui::SUI;
    use sui::table::{Self, Table, contains, borrow_mut};

    use deepbook::critbit::{Self, CritbitTree, borrow_mut_leaf_by_index, remove_leaf_by_index, borrow_leaf_by_index, borrow_leaf_by_key, find_leaf};
    use deepbook::custodian::{Self, Custodian, AccountCap};
    use deepbook::math::Self as clob_math;

    const MIN_ASK_ORDER_ID: u64 = 1 << 63;

    public struct LimitOrderPlaced has copy, store, drop {
        pool_id: ID,
        order_id: u64,
        price: u64,
        quantity: u64,
        is_bid: bool,
    }

    public fun place_limit_order<BaseAsset, QuoteAsset>(
        pool: &mut Pool<BaseAsset, QuoteAsset>,
        balance_manager: &mut BalanceManager,
        price: u64,
        quantity: u64,
        is_bid: bool,
        clock: &Clock,
        ctx: &mut TxContext
    ) {
        assert!(quantity > 0, EInvalidQuantity);
        assert!(price > 0, EInvalidTickPrice);

        let order_id = if is_bid {
            pool.next_bid_order_id()
        } else {
            pool.next_ask_order_id()
        };

        let order = if is_bid {
            balance_manager.lock_base_asset(quantity);
            BidOrder {
                order_id,
                price,
                quantity,
                user: tx_context::sender(ctx),
            }
        } else {
            balance_manager.lock_quote_asset(quantity * price);
            AskOrder {
                order_id,
                price,
                quantity,
                user: tx_context::sender(ctx),
            }
        };

        pool.add_order(order, is_bid);

        event::emit(LimitOrderPlaced {
            pool_id: object::id(pool),
            order_id,
            price,
            quantity,
            is_bid,
        });
    }
}

