module deepbook_example::market_order {
    use sui::tx_context::TxContext;
    use sui::coin::Coin;
    use sui::balance::Balance;
    use deepbook::deepbook::{Self, TradeProof, MarketOrderParams};
    use deepbook::deepbook::OrderType;
    use deepbook::deepbook::Side;
    use deepbook::deepbook::MarketOrderParams;
    use deepbook::deepbook::TradeProof;

    public entry fun execute_market_order(
        base_coin: Coin<u64>,
        quote_coin: Coin<u64>,
        pool_id: &sui::object::ID,
        side: Side,
        quantity: u64,
        ctx: &mut TxContext
    ) {
        let base_balance = Balance::from_coin(base_coin);
        let quote_balance = Balance::from_coin(quote_coin);

        let market_order_params = MarketOrderParams {
            side,
            quantity,
            order_type: OrderType::Market,
        };

        let trade_proof = deepbook::execute_market_order(
            pool_id,
            market_order_params,
            base_balance,
            quote_balance,
            ctx
        );

        TradeProof::destroy(trade_proof);
    }
}

