public fun execute_market_order<BaseType, QuoteType>(
    base_coin: Coin<BaseType>,
    quote_coin: Coin<QuoteType>,
    ctx: &mut TxContext
): (TradeProof, Coin<BaseType>, Coin<QuoteType>) {
    let base_balance = coin::into_balance(base_coin);
    let quote_balance = coin::into_balance(quote_coin);

    let (trade_proof, base_balance, quote_balance) = deepbook::execute_market_order(base_balance, quote_balance, ctx);

    let base_coin = coin::from_balance(base_balance, ctx);
    let quote_coin = coin::from_balance(quote_balance, ctx);

    (trade_proof, base_coin, quote_coin)
}

