module deepbook::limit_order {
    use sui::balance::{Self, Balance};
    use sui::coin::{Self, Coin};
    use sui::table::{Self, Table};
    use sui::transfer;
    use sui::tx_context::{Self, TxContext};
    use deepbook::custodian::{Self, AccountCap, Custodian};
    use deepbook::pool::{Self, Pool};
    use deepbook::types::{Order, OrderType, Side};

    public fun place_limit_order<T>(
        custodian: &mut Custodian<T>,
        pool: &mut Pool,
        account_cap: &AccountCap,
        quantity: u64,
        price: u64,
        is_bid: bool,
        expiration_timestamp: u64,
        ctx: &mut TxContext
    ) {
        let side = if (is_bid) Side::Bid else Side::Ask;
        let order_type = OrderType::Limit;

        // Check if user has enough balance
        let (available_balance, _) = custodian::account_balance(custodian, object::id(account_cap));
        assert!(available_balance >= quantity, 0);

        // Create order
        let order = Order {
            order_type,
            side,
            quantity,
            price,
            expiration_timestamp,
            owner: tx_context::sender(ctx),
            order_id: 0, // Will be set by pool
        };

        // Place order in pool
        pool::place_limit_order(pool, order, ctx);

        // Lock balance in custodian
        let account = table::borrow_mut(&mut custodian.account_balances, object::id(account_cap));
        let to_lock = balance::split(&mut account.available_balance, quantity);
        balance::join(&mut account.locked_balance, to_lock);
    }
}
