module deepbook_flashloan::flash_loan {
    use sui::tx_context::TxContext;
    use deepbook::custodian_v2::{Self, CustodianV2};
    use deepbook::deepcoin::{Self, DEEP};
    use deepbook::flash_loan_v3::{Self, FlashLoanReceipt};
    use sui::transfer;
    use sui::object::{Self, ID};

    public fun borrow_and_repay(
        custodian: &mut CustodianV2,
        amount: u64,
        ctx: &mut TxContext
    ) {
        // Borrow DEEP tokens via flash loan
        let receipt = flash_loan_v3::borrow<DEEP>(custodian, amount, ctx);

        // Get the borrowed DEEP coins
        let deep_coins = flash_loan_v3::get_borrowed_coins(&receipt);

        // Perform operations with borrowed coins here
        // (In a real scenario, you would use them for arbitrage, etc.)

        // Repay the flash loan by returning the same amount
        let (repaid_coins, remainder) = deepcoin::split(deep_coins, amount);
        flash_loan_v3::repay(receipt, repaid_coins);

        // Return any remaining coins to sender
        if (deepcoin::value(&remainder) > 0) {
            transfer::public_transfer(remainder, tx_context::sender(ctx));
        }
    }

    #[test]
    fun test_flash_loan() {
        let ctx = &mut tx_context::dummy();
        let custodian = custodian_v2::create_for_testing(ctx);
        let initial_deep = deepcoin::mint_test_coins<DEEP>(1000000, ctx);

        // Deposit some DEEP to enable flash loans
        custodian_v2::deposit(&mut custodian, initial_deep, ctx);

        // Test the flash loan
        borrow_and_repay(&mut custodian, 10000, ctx);
    }
}
