#[expected_failure(abort_code = deepbook_margin::tpsl::EMaxConditionalOrdersReached)]
fun test_error_max_conditional_orders_reached() {
    // Test EMaxConditionalOrdersReached: trying to add more than 10 orders (max is 10)

    let (
        mut scenario,
        clock,
        admin_cap,
        maintainer_cap,
        _usdc_pool_id,
        _sui_pool_id,
        _pool_id,
