        false,
        constants::max_u64(),
    );

    mm.add_conditional_order<SUI, USDC>(
        &pool,
        &sui_price,
        &usdc_price,
        &margin_registry,
        1,
        condition,
        pending_order,
        &clock,
        scenario.ctx(),
    );

    destroy_2!(sui_price, usdc_price);
    return_shared_2!(mm, pool);

    cleanup_margin_test(margin_registry, admin_cap, maintainer_cap, clock, scenario);
