    use sui::tx_context::TxContext;
    use deepbook::balance_manager::{Self, BalanceManager};
    use deepbook::custodian_v2::{Self, CustodianV2};
    use deepbook::pool::{Self, Pool};
    use deepbook::types::{OrderSide, OrderType, Self};

    public fun place_limit_order<BaseType, QuoteType>(
        pool: &mut Pool<BaseType, QuoteType>,
        balance_manager: &mut BalanceManager,
        custodian: &mut CustodianV2,
        base_coin: Coin<BaseType>,
        quote_coin: Coin<QuoteType>,
        price: u64,
        quantity: u64,
        is_bid: bool,
        expiration_timestamp: u64,
        order_type: u8,
        client_order_id: u64,
        ctx: &mut TxContext
    ) {
        let base_balance = balance::increase(balance_manager, coin::into_balance(base_coin));
        let quote_balance = balance::increase(balance_manager, coin::into_balance(quote_coin));

        let side = if (is_bid) OrderSide::Bid else OrderSide::Ask;
        let order_type = if (order_type == 0) OrderType::Limit else OrderType::PostOnly;

        pool::place_limit_order(
            pool,
            balance_manager,
            custodian,
            base_balance,
            quote_balance,
            price,
            quantity,
            side,
            expiration_timestamp,
            order_type,
            client_order_id,
            ctx
        );
    }
}
