    public fun execute_market_order<BaseCoin, QuoteCoin>(
        order_book: &mut OrderBook,
        base_coins: vector<Coin<BaseCoin>>,
        quote_coin_balance: &mut Balance<QuoteCoin>,
        quantity: u64,
        is_bid: bool,
        clock: &object::Clock,
        ctx: &mut TxContext
    ): (vector<Coin<BaseCoin>>, TradeProof) {
        let (base_coins_out, quote_coin_balance_out, trade_proof) = if (is_bid) {
            order_book.swap_exact_quote_for_base(
                base_coins,
                quote_coin_balance,
                quantity,
                clock,
                ctx
            )
        } else {
            order_book.swap_exact_base_for_quote(
                base_coins,
                quote_coin_balance,
                quantity,
                clock,
                ctx
            )
        };

        (base_coins_out, trade_proof)
    }

    public fun create_trade_proof(
        trade_proof: TradeProof,
        ctx: &mut TxContext
    ) {
        transfer::public_transfer(trade_proof, tx_context::sender(ctx));
    }
