    use deepbook::order_book::{Self, OrderBook};
    use deepbook::pool::{Self, Pool};
    use deepbook::utils::{Self, TradeProof};

    public fun execute_market_order<BaseAsset, QuoteAsset>(
        pool: &mut Pool<BaseAsset, QuoteAsset>,
        order_book: &mut OrderBook<BaseAsset, QuoteAsset>,
        custodian: &mut Custodian<BaseAsset, QuoteAsset>,
        base_coin: Coin<BaseAsset>,
        quote_coin: Coin<QuoteAsset>,
        side: u8,
        quantity: u64,
        ctx: &mut TxContext
    ): (TradeProof, Coin<BaseAsset>, Coin<QuoteAsset>) {
        let (base_balance, quote_balance) = custodian_v2::deposit_coins(custodian, base_coin, quote_coin, ctx);

        let order = order::new_market_order(
            side,
            quantity,
            order::new_order_options(false, false, false),
            ctx
        );

        let (trade_proof, filled_quantity, filled_amount) = clob_v2::place_market_order(
            pool,
            order_book,
            custodian,
            order,
            ctx
        );

        let (base_coin, quote_coin) = custodian_v2::withdraw_all(custodian, ctx);

        (trade_proof, base_coin, quote_coin)
    }
