module deepbook::market_order {
    use sui::tx_context::{Self, TxContext};
    use deepbook::trade_proof::{Self, TradeProof};
    use deepbook::order::{Self, Order};
    use deepbook::pool::{Self, Pool};
    use sui::coin::{Coin};
    use sui::balance::{Self, Balance};
    use sui::transfer;
    use sui::object::{Self, ID, UID};

    /// Executes a market order by creating a TradeProof and submitting it to the pool
    public entry fun execute_market_order<BaseType, QuoteType>(
        pool: &mut Pool<BaseType, QuoteType>,
        base_coins: vector<Coin<BaseType>>,
        quote_coins: vector<Coin<QuoteType>>,
        is_buy: bool,
        ctx: &mut TxContext
    ) {
        // Create a new trade proof
        let trade_proof = trade_proof::new(
            pool,
            base_coins,
            quote_coins,
            is_buy,
            ctx
        );

        // Execute the market order
        let (base_coin_out, quote_coin_out) = pool::execute_trade(
            pool,
            trade_proof,
            ctx
        );

        // Transfer the resulting coins back to the sender
        if (!vector::is_empty(&base_coin_out)) {
            transfer::public_transfer(object::take(base_coin_out), tx_context::sender(ctx));
        };
        if (!vector::is_empty(&quote_coin_out)) {
            transfer::public_transfer(object::take(quote_coin_out), tx_context::sender(ctx));
        };
    }

    /// Helper function to create a new order
    fun create_order<BaseType, QuoteType>(
        price: u64,
        quantity: u64,
        is_buy: bool,
        ctx: &mut TxContext
    ): Order<BaseType, QuoteType> {
        order::new(
            price,
            quantity,
            is_buy,
            tx_context::sender(ctx),
            ctx
        )
    }

    /// Helper function to create a trade proof from an order
    fun create_trade_proof_from_order<BaseType, QuoteType>(
        pool: &mut Pool<BaseType, QuoteType>,
        order: Order<BaseType, QuoteType>,
        ctx: &mut TxContext
    ): TradeProof<BaseType, QuoteType> {
        trade_proof::new_from_order(
            pool,
            order,
            ctx
        )
    }
}
