module deepbook_predict::order_placement;

use sui::balance_manager::BalanceManager;
use sui::deepbook::v3::pool::Pool;
use sui::deepbook::v3::order::{Order, OrderType, LimitOrder};
use sui::deepbook::v3::constants::{position_lot_size, float_scaling};
use sui::coin::Coin;
use sui::tx_context::TxContext;

public fun place_limit_order(
    balance_manager: &mut BalanceManager,
    pool: &mut Pool,
    coin: Coin,
    price: u64,
    quantity: u64,
    order_type: OrderType,
    ctx: &mut TxContext
) {
    assert!(quantity % position_lot_size() == 0, 0);

    let limit_order = LimitOrder {
        price,
        quantity,
        order_type,
    };

    let order = Order::Limit(limit_order);

    balance_manager.transfer_coin_to_pool(&mut coin, pool, ctx);
    pool.place_order(order, ctx);
}

