    use deepbook::custodian_v2::{Self, CustodianV2};
    use deepbook::pool::{Self, Pool};
    use deepbook::types::{Self, Order};
    use sui::coin::{Self, Coin};
    use sui::balance::{Self, Balance};
    use sui::transfer;
    use sui::object::{Self, ID};

    const FLASH_LOAN_FEE: u64 = 10; // 0.1% fee (10 basis points)

    public fun borrow_and_repay<DEEP>(
        pool: &mut Pool<DEEP>,
        custodian: &mut CustodianV2<DEEP>,
        amount: u64,
        ctx: &mut TxContext
    ) {
        // Borrow DEEP tokens
        let borrowed_coins = custodian_v2::withdraw(custodian, amount, ctx);

        // Do something with the borrowed coins (e.g., arbitrage, liquidation)
        // In a real implementation, this would contain your business logic

        // Calculate repayment amount (principal + fee)
        let repayment_amount = amount + (amount * FLASH_LOAN_FEE) / 10000;

        // Mint repayment coins (in reality you'd need to have these funds)
        let repayment_coin = coin::mint(ctx, repayment_amount);

        // Repay the loan
        custodian_v2::deposit(custodian, repayment_coin);

        // Clean up any remaining coins
        let balance = coin::into_balance(borrowed_coins);
        balance::destroy_zero(balance);
    }

    #[test_only]
    public fun test_flash_loan<DEEP>(
        pool: &mut Pool<DEEP>,
        custodian: &mut CustodianV2<DEEP>,
        ctx: &mut TxContext
    ) {
        let initial_balance = custodian_v2::balance(custodian);
        let loan_amount = initial_balance / 10; // Borrow 10% of available liquidity

        borrow_and_repay(pool, custodian, loan_amount, ctx);

        let final_balance = custodian_v2::balance(custodian);
        assert!(final_balance > initial_balance, 0); // Should have earned fees
    }
}
