module deepbook::limit_order {
    use deepbook::balance_manager::{Self, BalanceManager, TradeProof};
    use deepbook::vault::{Self, Vault};
    use sui::balance::{Self, Balance};
    use sui::coin::Coin;
    use sui::event;
    use sui::tx_context::TxContext;

    public fun place_limit_order<BaseAsset, QuoteAsset>(
        balance_manager: &mut BalanceManager<BaseAsset, QuoteAsset>,
        vault: &mut Vault<BaseAsset, QuoteAsset>,
        is_bid: bool,
        quantity: u64,
        price: u64,
        ctx: &mut TxContext
    ): (TradeProof, Balance<BaseAsset>, Balance<QuoteAsset>) {
        let (base_balance, quote_balance) = if (is_bid) {
            let quote_coin = balance::split(&mut vault.quote_balance, quantity * price, ctx);
            (balance::zero<BaseAsset>(), balance::from_coin(quote_coin))
        } else {
            let base_coin = balance::split(&mut vault.base_balance, quantity, ctx);
            (balance::from_coin(base_coin), balance::zero<QuoteAsset>())
        };

        let (trade_proof, base_balance, quote_balance) = balance_manager::place_limit_order(
            balance_manager,
            is_bid,
            quantity,
            price,
            base_balance,
            quote_balance,
            ctx
        );

        event::emit(trade_proof);
        (trade_proof, base_balance, quote_balance)
    }

    public fun settle_limit_order<BaseAsset, QuoteAsset>(
        balance_manager: &mut BalanceManager<BaseAsset, QuoteAsset>,
        vault: &mut Vault<BaseAsset, QuoteAsset>,
        trade_proof: TradeProof,
        base_balance: Balance<BaseAsset>,
        quote_balance: Balance<QuoteAsset>,
    ) {
        if (balance::value(&base_balance) > 0) {
            vault.base_balance = balance::join(&mut vault.base_balance, base_balance);
        };
        if (balance::value(&quote_balance) > 0) {
            vault.quote_balance = balance::join(&mut vault.quote_balance, quote_balance);
        };

        balance_manager::settle(balance_manager, trade_proof);
    }
}

