module deepbook_example::market_order {
    use sui::tx_context::TxContext;
    use deepbook::market::{Self, Market};
    use deepbook::order::{Self, Order};
    use deepbook::custodian::{Self, Custodian};
    use deepbook::types::{Self, Side, OrderType};
    use deepbook::utils;
    use sui::balance::{Self, Balance};
    use sui::coin::{Self, Coin};
    use sui::sui::SUI;
    use sui::transfer;
    use sui::object::{Self, ID};

    /// Execute a market order on DeepBook v3
    public entry fun execute_market_order(
        market: &mut Market,
        custodian: &mut Custodian,
        side: u8,
        quantity: u64,
        base_coin: Coin<SUI>,
        clock: &Clock,
        ctx: &mut TxContext
    ) {
        let side = if (side == 0) Side::Ask else Side::Bid;
        let order_type = OrderType::Market;

        // Create order
        let order = order::new(
            side,
            order_type,
            quantity,
            0, // price not needed for market orders
            utils::order_expiration_time(clock),
            ctx
        );

        // Create trade proof
        let trade_proof = market::create_trade_proof(market, ctx);

        // Execute market order
        let (remaining_order, base_coin_change, quote_coin_change) = market::execute_order(
            market,
            custodian,
            order,
            trade_proof,
            base_coin,
            clock,
            ctx
        );

        // Handle remaining order if any
        if (order::quantity(&remaining_order) > 0) {
            let order_id = object::id(&remaining_order);
            transfer::public_transfer(remaining_order, tx_context::sender(ctx));
        } else {
            order::destroy_zero_quantity(remaining_order);
        }

        // Return coins to sender
        if (balance::value(&base_coin_change) > 0) {
            transfer::public_transfer(base_coin_change, tx_context::sender(ctx));
        }
        if (balance::value(&quote_coin_change) > 0) {
            transfer::public_transfer(quote_coin_change, tx_context::sender(ctx));
        }
    }

    /// Helper function to create a new market order
    public fun create_market_order(
        side: Side,
        quantity: u64,
        ctx: &mut TxContext
    ): Order {
        order::new(
            side,
            OrderType::Market,
            quantity,
            0, // price not needed for market orders
            0, // immediate execution
            ctx
        )
    }

    /// Helper function to create trade proof
    public fun create_trade_proof(
        market: &mut Market,
        ctx: &mut TxContext
    ): types::TradeProof {
        market::create_trade_proof(market, ctx)
    }
}
