    /// TradeProof is a proof that a trade was executed.
    public struct TradeProof has copy, drop, store {
        order_id: u128,
        client_order_id: u64,
        quantity: u64,
        price: u64,
        timestamp: u64
    }

    /// Executes a market order on DeepBook v3 and creates a TradeProof.
    public fun execute_market_order(
        pool: &mut UID,
        balances: &mut Balances,
        order: Order,
        ctx: &mut TxContext
    ): (Order, TradeProof) {
        let (remaining_order, fills) = order::execute_order(pool, balances, order, ctx);

        // Create TradeProof from the executed order
        let trade_proof = TradeProof {
            order_id: remaining_order.order_id,
            client_order_id: remaining_order.client_order_id,
            quantity: remaining_order.quantity - remaining_order.filled_quantity,
            price: order::get_price(&remaining_order),
            timestamp: sui::clock::timestamp_ms(ctx)
        };

        event::emit(trade_proof);

        (remaining_order, trade_proof)
    }

    /// Helper function to create a new market order
    public fun new_market_order(
        balance_manager_id: ID,
        order_id: u128,
        client_order_id: u64,
        quantity: u64,
        is_bid: bool,
        expire_timestamp: u64,
        ctx: &mut TxContext
    ): Order {
        let order_deep_price = order::new_order_deep_price(is_bid, 0); // Market order has price 0
        let status = constants::ORDER_STATUS_ACTIVE;

        Order {
            balance_manager_id,
            order_id,
            client_order_id,
            quantity,
            filled_quantity: 0,
            fee_is_deep: false,
            order_deep_price,
            epoch: 0,
            status,
            expire_timestamp
        }
    }

    /// Public entry function to execute a market order
    public entry fun execute_market_order_entry(
        pool: &mut UID,
        balances: &mut Balances,
        balance_manager_id: ID,
        order_id: u128,
        client_order_id: u64,
        quantity: u64,
        is_bid: bool,
        expire_timestamp: u64,
        ctx: &mut TxContext
    ) {
        let order = new_market_order(
            balance_manager_id,
            order_id,
            client_order_id,
            quantity,
            is_bid,
            expire_timestamp,
            ctx
        );
        let (_, trade_proof) = execute_market_order(pool, balances, order, ctx);
        event::emit(trade_proof);
    }
}
