    use deepbook::types::{Self, Side};

    /// Flash loan error codes
    const EFlashLoanFailed: u64 = 0;
    const ERepaymentFailed: u64 = 1;

    /// Struct representing a flash loan receipt
    public struct FlashLoanReceipt<phantom T> has key {
        id: ID,
        borrow_receipt: BorrowReceipt<T>,
        amount: u64
    }

    /// Borrow DEEP tokens via flash loan
    public fun borrow_flash<T>(
        pool: &mut Pool<T>,
        amount: u64,
        ctx: &mut TxContext
    ): FlashLoanReceipt<T> {
        let borrow_receipt = custodian_v2::borrow(pool, amount, ctx);
        FlashLoanReceipt {
            id: object::new(ctx),
            borrow_receipt,
            amount
        }
    }

    /// Repay the flash loan
    public fun repay_flash<T>(
        receipt: FlashLoanReceipt<T>,
        payment: Coin<T>,
        pool: &mut Pool<T>,
    ) {
        let FlashLoanReceipt { id, borrow_receipt, amount } = receipt;
        object::delete(id);

        // Verify repayment amount matches borrowed amount
        assert!(coin::value(&payment) == amount, ERepaymentFailed);

        custodian_v2::repay_with_coin(borrow_receipt, payment, pool);
    }

    /// Example of a complete flash loan transaction
    public entry fun execute_flash_loan<T>(
        pool: &mut Pool<T>,
        amount: u64,
        ctx: &mut TxContext
    ) {
        // 1. Borrow tokens
        let receipt = borrow_flash(pool, amount, ctx);

        // 2. Do something with the borrowed tokens (placeholder)
        // In a real scenario, you would implement your logic here
        // and ensure you have enough tokens to repay the loan

        // 3. Create repayment coin (in reality, this would come from your operations)
        let payment = coin::take(&mut balance::increase_supply(coin::balance_mut(&mut coin::from_balance(
            balance::zero<T>(),
            ctx
        ))), amount);

        // 4. Repay the loan
        repay_flash(receipt, payment, pool);
    }
}

