            custodian,
            base_coin,
            quote_coin,
            ctx
        );

        let order = order::new_limit_order(
            side,
            price,
            quantity,
            *balance::value(&base_balance),
            *balance::value(&quote_balance),
            ctx
        );

        pool::place_order(pool, order)
