module deepbook_trader::market_order {
    use sui::tx_context::TxContext;
    use sui::coin::Coin;
    use sui::balance::Balance;
    use sui::transfer;
    use sui::object::{Self, UID};
    use deepbook::custodian_v2::AccountCap;
    use deepbook::pool_v2::Pool;
    use deepbook::utils;
    use deepbook::critbit;
    use deepbook::order;
    use deepbook::types;

    /// Proof that a trade was executed
    public struct TradeProof has drop, store {}

    /// Executes a market order on DeepBook
    public fun execute_market_order<BaseType, QuoteType>(
        pool: &mut Pool<BaseType, QuoteType>,
        account_cap: &AccountCap,
        base_coins: Coin<BaseType>,
        quote_coins: Coin<QuoteType>,
        is_bid: bool,
        quantity: u64,
        ctx: &mut TxContext
    ): (TradeProof, Coin<BaseType>, Coin<QuoteType>) {
        let (base_balance, quote_balance) = if (is_bid) {
            let quote_balance = Balance::join(Balance::from_coin(quote_coins), pool.quote_balance);
            (Balance::from_coin(base_coins), quote_balance)
        } else {
            let base_balance = Balance::join(Balance::from_coin(base_coins), pool.base_balance);
            (base_balance, Balance::from_coin(quote_coins))
        };

        let (new_base_balance, new_quote_balance, _filled_order_id_vec) = if (is_bid) {
            pool.swap_exact_quote_for_base(
                account_cap,
                quote_balance,
                quantity,
                ctx
            )
        } else {
            pool.swap_exact_base_for_quote(
                account_cap,
                base_balance,
                quantity,
                ctx
            )
        };

        let (remaining_base, remaining_quote) = if (is_bid) {
            let base_coin = Balance::into_coin(new_base_balance);
            let quote_coin = if (Balance::value(&new_quote_balance) > 0) {
                Balance::into_coin(new_quote_balance)
            } else {
                utils::empty_coin<QuoteType>(ctx)
            };
            (base_coin, quote_coin)
        } else {
            let quote_coin = Balance::into_coin(new_quote_balance);
            let base_coin = if (Balance::value(&new_base_balance) > 0) {
                Balance::into_coin(new_base_balance)
            } else {
                utils::empty_coin<BaseType>(ctx)
            };
            (base_coin, quote_coin)
        };

        (TradeProof {}, remaining_base, remaining_quote)
    }

    #[test_only]
    public fun test_execute_market_order<BaseType, QuoteType>(
        pool: &mut Pool<BaseType, QuoteType>,
        account_cap: &AccountCap,
        base_coins: Coin<BaseType>,
        quote_coins: Coin<QuoteType>,
        is_bid: bool,
        quantity: u64,
        ctx: &mut TxContext
    ): (TradeProof, Coin<BaseType>, Coin<QuoteType>) {
        execute_market_order(pool, account_cap, base_coins, quote_coins, is_bid, quantity, ctx)
    }
}

