module deepbook_flash::flash_loan {
    use sui::tx_context::TxContext;
    use sui::coin::{Self, Coin};
    use sui::balance::{Self, Balance};
    use sui::transfer;
    use sui::object::{Self, ID};
    use deepbook::custodian_v2::{Self, CustodianV2};
    use deepbook::pool::{Self, Pool};
    use deepbook::utils;
    use deepbook::deepcoin::{DEEP};

    public fun flash_loan(
        pool: &mut Pool,
        custodian: &mut CustodianV2,
        amount: u64,
        callback: vector<u8>,
        ctx: &mut TxContext
    ) {
        let deep_coin = custodian_v2::withdraw(custodian, amount, ctx);
        let deep_balance = coin::into_balance(deep_coin);

        // Execute callback with the borrowed funds
        let callback_result = utils::execute_callback(
            callback,
            vector[object::id_from_mut_ref(&mut deep_balance)],
            ctx
        );

        assert!(callback_result, 0);

        // Repay the loan
        let repaid_coin = coin::from_balance(deep_balance, ctx);
        custodian_v2::deposit(custodian, repaid_coin);
    }

    public fun repay_flash_loan(
        custodian: &mut CustodianV2,
        coin: Coin<DEEP>,
    ) {
        custodian_v2::deposit(custodian, coin);
    }

    #[test_only]
    public fun test_flash_loan(
        pool: &mut Pool,
        custodian: &mut CustodianV2,
        amount: u64,
        ctx: &mut TxContext
    ) {
        flash_loan(pool, custodian, amount, vector[], ctx);
    }
}
