```move
module deepbook::market_order {
    use sui::tx_context::TxContext;
    use deepbook::trade_proof::{Self, TradeProof};
    use deepbook::order::{Self, Order};
    use deepbook::pool::{Self, Pool};
    use deepbook::utils;
    use sui::coin::{Coin};
    use sui::balance::{Balance};
    use sui::sui::SUI;
    use sui::object::{ID, UID};
    use sui::transfer;
    use sui::vec_map::{Self, VecMap};

    public struct MarketOrderResult<phantom BaseAsset, phantom QuoteAsset> has copy, drop {
        pub base_coin: Coin<BaseAsset>,
        pub quote_coin: Coin<QuoteAsset>,
        pub trade_proof: TradeProof,
    }

    public fun execute_market_order<BaseAsset, QuoteAsset>(
        pool: &mut Pool<BaseAsset, QuoteAsset>,
        base_coin: Coin<BaseAsset>,
        quote_coin: Coin<QuoteAsset>,
        is_buy: bool,
        ctx: &mut TxContext,
    ): MarketOrderResult<BaseAsset, QuoteAsset> {
        let (base_balance, quote_balance) = if (is_buy) {
            let base_balance = coin::into_balance(base_coin);
            let quote_balance = coin::into_balance(quote_coin);
            (base_balance, quote_balance)
        } else {
            let quote_balance = coin::into_balance(quote_coin);
            let base_balance = coin::into_balance(base_coin);
            (base_balance, quote_balance)
        };

        let order = order::new_market(
            if (is_buy) quote_balance else base_balance,
            is_buy,
            ctx,
        );

        let (new_base_balance, new_quote_balance, trade_proof) = pool.execute_order(order, ctx);

        let (result_base_coin, result_quote_coin) = if (is_buy) {
            let base_coin = coin::from_balance(new_base_balance, ctx);
            let quote_coin = coin::from_balance(new_quote_balance, ctx);
            (base_coin, quote_coin)
        } else {
            let quote_coin = coin::from_balance(new_quote_balance, ctx);
            let base_coin = coin::from_balance(new_base_balance, ctx);
            (base_coin, quote_coin)
        };

        MarketOrderResult {
            base_coin: result_base_coin,
            quote_coin: result_quote_coin,
            trade_proof,
        }
    }

    public entry fun execute_market_order_entry<BaseAsset, QuoteAsset>(
        pool: &mut Pool<BaseAsset, QuoteAsset>,
        base_coin: Coin<BaseAsset>,
        quote_coin: Coin<QuoteAsset>,
        is_buy: bool,
        ctx: &mut TxContext,
    ) {
        let MarketOrderResult {
            base_coin,
            quote_coin,
            trade_proof: _,
        } = execute_market_order(pool, base_coin, quote_coin, is_buy, ctx);

        transfer::public_transfer(base_coin, tx_context::sender(ctx));
        transfer::public_transfer(quote_coin, tx_context::sender(ctx));
    }

    public fun create_trade_proof(
        pool_id: ID,
        order_id: u64,
        base_asset_filled: u64,
        quote_asset_filled: u64,
        fee_amount: u64,
        ctx: &mut TxContext,
    ): TradeProof {
        trade_proof::new(
            pool_id,
            order_id,
            base_asset_filled,
            quote_asset_filled,
            fee_amount,
            ctx,
        )
    }
}
