module deepbook::market_order {
    use sui::tx_context::{Self, TxContext};
    use sui::coin::{Self, Coin};
    use sui::balance::{Self, Balance};
    use sui::transfer;
    use sui::object::{Self, ID};
    use deepbook::trade_params::{Self, TradeParams};
    use deepbook::custodian_v2::{Self, CustodianV2};
    use deepbook::clob_v2::{Self, Pool};
    use deepbook::order::{Self, Order};
    use deepbook::trade_proof::{Self, TradeProof};
    use deepbook::constants;

    public fun execute_market_order<BaseType, QuoteType>(
        pool: &mut Pool<BaseType, QuoteType>,
        custodian: &mut CustodianV2<BaseType, QuoteType>,
        base_coins: vector<Coin<BaseType>>,
        quote_coins: vector<Coin<QuoteType>>,
        quantity: u64,
        is_bid: bool,
        clock: &clock::Clock,
        ctx: &mut TxContext
    ): (TradeProof, Option<Coin<BaseType>>, Option<Coin<QuoteType>>) {
        let trade_params = trade_params::new(
            2_000_000, // taker_fee: 0.2%
            500_000,   // maker_fee: 0.05%
            100 * constants::deep_unit() // stake_required
        );

        let (base_balance, quote_balance) = if (is_bid) {
            let base_balance = balance::zero<BaseType>();
            let quote_balance = coin::into_balance(quote_coins);
            (base_balance, quote_balance)
        } else {
            let base_balance = coin::into_balance(base_coins);
            let quote_balance = balance::zero<QuoteType>();
            (base_balance, quote_balance)
        };

        let order = order::new_market_order(
            quantity,
            is_bid,
            tx_context::sender(ctx),
            clock
        );

        let (trade_proof, base_balance, quote_balance) = clob_v2::swap(
            pool,
            custodian,
            order,
            base_balance,
            quote_balance,
            &trade_params,
            clock,
            ctx
        );

        let base_coin = if (balance::value(&base_balance) > 0) {
            let coin = coin::from_balance(base_balance, ctx);
            option::some(coin)
        } else {
            option::none()
        };

        let quote_coin = if (balance::value(&quote_balance) > 0) {
            let coin = coin::from_balance(quote_balance, ctx);
            option::some(coin)
        } else {
            option::none()
        };

        (trade_proof, base_coin, quote_coin)
    }
}
