// Compiler error: Circular dependency detected between modules 'a' and 'b'

```move
module 0x1::a {
    use 0x1::b;

    public fun foo() {
        b::bar();
    }
}

module 0x1::b {
    use 0x1::a;

    public fun bar() {
        a::foo();
    }
}
```

output:
```move
module 0x1::a {
    use 0x1::b;

    public fun foo(witness: Witness) {
        b::bar(witness);
    }

    struct Witness has drop {}
}

module 0x1::b {
    public fun bar(_witness: Witness) {
        // No longer needs to call back to module a
    }

    struct Witness has drop {}
}
```
// The fix works by breaking the circular dependency through the use of a witness struct that is passed between modules, preventing direct mutual calls.

