module deepbook::limit_order {
    use sui::balance::{Self, Balance};
    use sui::coin::{Self, Coin};
    use sui::tx_context::TxContext;
    use deepbook::trade_params::{Self, TradeParams};
    use deepbook::pool::{Self, Pool};
    use deepbook::balance_manager::{Self, BalanceManager};
    use deepbook::order::{Self, Order, OrderType};

    /// Places a limit order on a DeepBook pool.
    /// Returns the order ID and remaining balance.
    public fun place_limit_order<BaseType, QuoteType>(
        pool: &mut Pool<BaseType, QuoteType>,
        balance_manager: &mut BalanceManager,
        trade_params: &TradeParams,
        base_coin: Coin<BaseType>,
        quote_coin: Coin<QuoteType>,
        price: u64,
        quantity: u64,
        is_bid: bool,
        expiration_timestamp: u64,
        ctx: &mut TxContext
    ): (u64, Balance<BaseType>, Balance<QuoteType>) {
        let (base_balance, quote_balance) = balance_manager.deposit_coins(base_coin, quote_coin, ctx);

        let order_type = if is_bid {
            order::bid_limit(price, expiration_timestamp)
        } else {
            order::ask_limit(price, expiration_timestamp)
        };

        let order = order::new(
            *balance::value(&base_balance),
            *balance::value(&quote_balance),
            quantity,
            order_type,
            trade_params::maker_fee(trade_params),
            trade_params::taker_fee(trade_params),
            ctx
        );

        let order_id = pool::place_order(pool, order);

        (order_id, base_balance, quote_balance)
    }

    /// Places a limit order using balances instead of coins.
    public fun place_limit_order_with_balances<BaseType, QuoteType>(
        pool: &mut Pool<BaseType, QuoteType>,
        balance_manager: &mut BalanceManager,
        trade_params: &TradeParams,
        base_balance: Balance<BaseType>,
        quote_balance: Balance<QuoteType>,
        price: u64,
        quantity: u64,
        is_bid: bool,
        expiration_timestamp: u64,
        ctx: &mut TxContext
    ): (u64, Balance<BaseType>, Balance<QuoteType>) {
        let order_type = if is_bid {
            order::bid_limit(price, expiration_timestamp)
        } else {
            order::ask_limit(price, expiration_timestamp)
        };

        let order = order::new(
            *balance::value(&base_balance),
            *balance::value(&quote_balance),
            quantity,
            order_type,
            trade_params::maker_fee(trade_params),
            trade_params::taker_fee(trade_params),
            ctx
        );

        let order_id = pool::place_order(pool, order);

        (order_id, base_balance, quote_balance)
    }
}
