module deepbook::market_order {
    use deepbook::balance_manager::{Self, BalanceManager};
    use deepbook::pool::{Self, Pool};
    use deepbook::trade_proof::{Self, TradeProof};
    use sui::coin::Coin;
    use sui::balance::{Self, Balance};
    use sui::tx_context::TxContext;
    use sui::dynamic_field as df;
    use sui::object::{Self, ID};

    public fun execute_market_order<BaseType, QuoteType>(
        pool: &mut Pool<BaseType, QuoteType>,
        balance_manager: &mut BalanceManager,
        base_coin: Coin<BaseType>,
        quote_coin: Coin<QuoteType>,
        is_bid: bool,
        ctx: &mut TxContext
    ): (TradeProof, Balance<BaseType>, Balance<QuoteType>) {
        let base_balance = balance::from_coin(base_coin);
        let quote_balance = balance::from_coin(quote_coin);

        let trade_proof = trade_proof::new(balance_manager, ctx);

        if (is_bid) {
            pool::place_market_bid(
                pool,
                &mut trade_proof,
                base_balance,
                quote_balance,
                ctx
            )
        } else {
            pool::place_market_ask(
                pool,
                &mut trade_proof,
                base_balance,
                quote_balance,
                ctx
            )
        };

        (trade_proof, base_balance, quote_balance)
    }

    public entry fun execute_market_bid<BaseType, QuoteType>(
        pool: &mut Pool<BaseType, QuoteType>,
        balance_manager: &mut BalanceManager,
        base_coin: Coin<BaseType>,
        quote_coin: Coin<QuoteType>,
        ctx: &mut TxContext
    ) {
        let (trade_proof, base_balance, quote_balance) = execute_market_order(
            pool,
            balance_manager,
            base_coin,
            quote_coin,
            true,  // is_bid
            ctx
        );
        trade_proof::destroy(trade_proof);
        balance::destroy(base_balance);
        balance::destroy(quote_balance);
    }

    public entry fun execute_market_ask<BaseType, QuoteType>(
        pool: &mut Pool<BaseType, QuoteType>,
        balance_manager: &mut BalanceManager,
        base_coin: Coin<BaseType>,
        quote_coin: Coin<QuoteType>,
        ctx: &mut TxContext
    ) {
