    use deepbook::utils;

    public fun place_limit_order<BaseCoin, QuoteCoin>(
        book: &mut Book,
        balance_manager: &mut BalanceManager,
        is_bid: bool,
        price: u64,
        quantity: u64,
        base_coin: Coin<BaseCoin>,
        quote_coin: Coin<QuoteCoin>,
        ctx: &mut TxContext
    ) {
        let base_balance = balance_manager.new_balance(coin::into_balance(base_coin));
        let quote_balance = balance_manager.new_balance(coin::into_balance(quote_coin));

        let order_info = order_info::new(
            if (is_bid) book.next_bid_order_id else book.next_ask_order_id,
            price,
            quantity,
            is_bid,
            tx_context::sender(ctx),
            tx_context::epoch(ctx)
        );

        let order = order::new(order_info, base_balance, quote_balance);

        if (is_bid) {
            book.next_bid_order_id = book.next_bid_order_id + 1;
            big_vector::push_back(&mut book.bids, order);
        } else {
            book.next_ask_order_id = book.next_ask_order_id + 1;
            big_vector::push_back(&mut book.asks, order);
        };
    }
}
