    let output1 = gen.generate_bytes(10);
    let output2 = gen.generate_bytes(10);
    i = 0;
    loop {
        // should break before the overflow
        if (&output1[i] != &output2[i]) break;
        i = i + 1;
    };

    test_scenario::return_shared(random_state);
