module deepbook::limit_order {
    use sui::balance_manager::BalanceManager;
    use sui::coin::Coin;
    use sui::tx_context::TxContext;
    use deepbook::pool::Pool;
    use deepbook::order::{Order, OrderSide};
    use deepbook::price::{Price, PriceTier};
    use deepbook::quantity::Quantity;

    public fun place_limit_order<BaseCoin, QuoteCoin>(
        pool: &mut Pool<BaseCoin, QuoteCoin>,
        balance_manager: &mut BalanceManager,
        side: OrderSide,
        price: u64,
        quantity: u64,
        ctx: &mut TxContext
    ) {
        let price_obj = Price::new(price);
        let quantity_obj = Quantity::new(quantity);
        let price_tier = PriceTier::from_price(price_obj);

        let order = Order::new_limit_order(
            side,
            price_obj,
            quantity_obj,
            price_tier,
            ctx
        );

        let (base_coin, quote_coin) = if (side == OrderSide::Bid) {
            let quote_coin = balance_manager.withdraw_quote::<QuoteCoin>(price * quantity, ctx);
            (balance_manager.base_balance<BaseCoin>(), quote_coin)
        } else {
            let base_coin = balance_manager.withdraw_base::<BaseCoin>(quantity, ctx);
            (base_coin, balance_manager.quote_balance<QuoteCoin>())
        };

        pool.place_order(
            order,
            base_coin,
            quote_coin,
            ctx
        );
    }
}
