public macro fun num_checked_shr<$T>($x: $T, $shift: u8, $bit_size: u8): Option<$T> {
    let x = $x;
    let shift = $shift;
    let bit_size = $bit_size;
    if (shift >= bit_size) option::none() else option::some(x >> shift)
