public macro fun num_lossless_shr<$T>($x: $T, $shift: u8, $bit_size: u8): Option<$T> {
    let x = $x;
    let shift = $shift;
    let bit_size = $bit_size;
    if (shift >= bit_size) option::none()
    else {
        let result = x >> shift;
        if (result << shift == x) option::some(result) else option::none()
