}

public fun interest_rate(
    utilization_rate: u64,
    base_rate: u64,
    base_slope: u64,
    optimal_utilization: u64,
    excess_slope: u64,
): u64 {
    if (utilization_rate < optimal_utilization) {
        // Use base slope
        math::mul(utilization_rate, base_slope) + base_rate
    } else {
        // Use base slope and excess slope
        let excess_utilization = utilization_rate - optimal_utilization;
        let excess_rate = math::mul(excess_utilization, excess_slope);

        base_rate + math::mul(optimal_utilization, base_slope) + excess_rate
    }
}

/// Setup a complete margin trading environment with margin manager for pool proxy testing
/// Returns: (scenario, clock, admin_cap, maintainer_cap, base_pool_id, quote_pool_id, deepbook_pool_id, registry_id)
public fun setup_pool_proxy_test_env<BaseAsset, QuoteAsset>(): (
    Scenario,
    Clock,
    MarginAdminCap,
    MaintainerCap,
    ID,
    ID,
    ID,
    ID,
) {
    let (mut scenario, mut clock, admin_cap, maintainer_cap) = setup_margin_registry();

    clock.set_for_testing(1000000);

    // Create margin pools
    let base_pool_id = create_margin_pool<BaseAsset>(
        &mut scenario,
        &maintainer_cap,
        default_protocol_config(),
        &clock,
    );
    let quote_pool_id = create_margin_pool<QuoteAsset>(
        &mut scenario,
        &maintainer_cap,
        default_protocol_config(),
        &clock,
    );

    // Get pool caps
    let (base_pool_cap, quote_pool_cap) = get_margin_pool_caps(&mut scenario, base_pool_id);

    // Create DeepBook pool
    let (pool_id, registry_id) = create_pool_for_testing<BaseAsset, QuoteAsset>(&mut scenario);

    // Set up deep price data for the pool (required for get_quote_quantity_out).
    // Skip if DEEP is one of the pool's assets - DEEP pools can use their own trades for deep price.
    let base_is_deep =
        std::type_name::with_defining_ids<BaseAsset>() == std::type_name::with_defining_ids<DEEP>();
    let quote_is_deep =
        std::type_name::with_defining_ids<QuoteAsset>() == std::type_name::with_defining_ids<DEEP>();
    if (!base_is_deep && !quote_is_deep) {
        setup_deep_price<BaseAsset, QuoteAsset>(&mut scenario, pool_id, registry_id, &clock);
    };

    // Enable margin trading
    scenario.next_tx(test_constants::admin());
    let mut registry = scenario.take_shared<MarginRegistry>();
    enable_deepbook_margin_on_pool<BaseAsset, QuoteAsset>(
        pool_id,
        &mut registry,
        &admin_cap,
        &clock,
        &mut scenario,
    );

    // Initialize price for the pool (required for price protection)
    initialize_pool_price<BaseAsset, QuoteAsset>(pool_id, &mut registry, &clock, &mut scenario);

    return_shared(registry);

    // Setup liquidity for margin pools
    scenario.next_tx(test_constants::admin());
    let mut base_pool = scenario.take_shared_by_id<MarginPool<BaseAsset>>(base_pool_id);
    let mut quote_pool = scenario.take_shared_by_id<MarginPool<QuoteAsset>>(quote_pool_id);
    let registry = scenario.take_shared<MarginRegistry>();
    let supplier_cap = margin_pool::mint_supplier_cap(&registry, &clock, scenario.ctx());

    base_pool.supply(
        &registry,
        &supplier_cap,
        mint_coin<BaseAsset>(1_000_000 * test_constants::usdc_multiplier(), scenario.ctx()),
        option::none(),
        &clock,
    );
    quote_pool.supply(
        &registry,
        &supplier_cap,
        mint_coin<QuoteAsset>(1_000_000 * test_constants::usdt_multiplier(), scenario.ctx()),
        option::none(),
        &clock,
    );

    base_pool.enable_deepbook_pool_for_loan(&registry, pool_id, &base_pool_cap, &clock);
    quote_pool.enable_deepbook_pool_for_loan(&registry, pool_id, &quote_pool_cap, &clock);

    return_shared_2!(base_pool, quote_pool);
    return_shared(registry);
    return_to_sender_2!(&scenario, base_pool_cap, quote_pool_cap);
    destroy(supplier_cap);

    (scenario, clock, admin_cap, maintainer_cap, base_pool_id, quote_pool_id, pool_id, registry_id)
}

/// Set up orderbook liquidity for market orders (USDC/USDT at ~1.0 price)
public fun setup_orderbook_liquidity_stablecoin<BaseAsset, QuoteAsset>(
    scenario: &mut Scenario,
    pool_id: ID,
    clock: &Clock,
) {
    use deepbook::balance_manager;

    scenario.next_tx(test_constants::user2());
    let mut pool = scenario.take_shared_by_id<Pool<BaseAsset, QuoteAsset>>(pool_id);
    let mut balance_manager = balance_manager::new(scenario.ctx());

    // Deposit assets for liquidity provision
    balance_manager.deposit(
        mint_coin<BaseAsset>(1_000_000 * test_constants::usdc_multiplier(), scenario.ctx()),
        scenario.ctx(),
    );
    balance_manager.deposit(
        mint_coin<QuoteAsset>(1_000_000 * test_constants::usdt_multiplier(), scenario.ctx()),
        scenario.ctx(),
    );
    balance_manager.deposit(
        mint_coin<DEEP>(10000 * test_constants::deep_multiplier(), scenario.ctx()),
        scenario.ctx(),
    );

    let trade_proof = balance_manager.generate_proof_as_owner(scenario.ctx());

    // Place ask orders (sell base) slightly above oracle (within 5% tolerance)
    pool.place_limit_order<BaseAsset, QuoteAsset>(
        &mut balance_manager,
        &trade_proof,
        1,
        constants::no_restriction(),
        constants::self_matching_allowed(),
        1_010_000_000, // $1.01 (1% above oracle, within 5% tolerance)
        10000 * test_constants::usdc_multiplier(),
        false, // is_bid = false (ask)
        false,
        constants::max_u64(),
        clock,
        scenario.ctx(),
    );

    // Place bid orders slightly below oracle (within 5% tolerance)
    pool.place_limit_order<BaseAsset, QuoteAsset>(
        &mut balance_manager,
        &trade_proof,
        2,
        constants::no_restriction(),
        constants::self_matching_allowed(),
        990_000_000, // $0.99 (1% below oracle, within 5% tolerance)
        10000 * test_constants::usdc_multiplier(),
        true, // is_bid = true
        false,
        constants::max_u64(),
        clock,
        scenario.ctx(),
    );

    transfer::public_transfer(balance_manager, test_constants::user2());
    return_shared(pool);
}

