/// Sets up deep price data for a pool by creating a USDC/DEEP reference pool.
/// This is required for pools to use get_quote_quantity_out which needs deep price data.
/// Returns the reference pool ID for cleanup.
public fun setup_deep_price<BaseAsset, QuoteAsset>(
    scenario: &mut Scenario,
    target_pool_id: ID,
    registry_id: ID,
    clock: &Clock,
): ID {
    use deepbook::balance_manager;

    // Create whitelisted USDC/DEEP reference pool (whitelisted pools don't need deep price to place orders)
    scenario.next_tx(test_constants::admin());
    let admin_cap = registry::get_admin_cap_for_testing(scenario.ctx());
    let mut registry = scenario.take_shared_by_id<Registry>(registry_id);
    let reference_pool_id = pool::create_pool_admin<USDC, DEEP>(
        &mut registry,
        constants::tick_size(),
        constants::lot_size(),
        constants::min_size(),
        true, // whitelisted_pool
        false, // stable_pool
        &admin_cap,
        scenario.ctx(),
    );
    return_shared(registry);
    destroy(admin_cap);

    // Set up liquidity in the reference pool for mid_price calculation
    scenario.next_tx(test_constants::user2());
    let mut reference_pool = scenario.take_shared_by_id<Pool<USDC, DEEP>>(reference_pool_id);
    let mut balance_manager = balance_manager::new(scenario.ctx());

    balance_manager.deposit(
        mint_coin<USDC>(1_000_000 * test_constants::usdc_multiplier(), scenario.ctx()),
        scenario.ctx(),
    );
    balance_manager.deposit(
        mint_coin<DEEP>(1_000_000 * test_constants::deep_multiplier(), scenario.ctx()),
        scenario.ctx(),
    );

    let trade_proof = balance_manager.generate_proof_as_owner(scenario.ctx());

    // Place bid slightly below mid price (spread to prevent matching)
    reference_pool.place_limit_order<USDC, DEEP>(
        &mut balance_manager,
        &trade_proof,
        1,
        constants::no_restriction(),
        constants::self_matching_allowed(),
        9_000_000, // 0.009 * 1e9 (bid below)
        100 * test_constants::deep_multiplier(),
        true, // is_bid
        true, // pay_with_deep
        constants::max_u64(),
        clock,
        scenario.ctx(),
    );

    // Place ask slightly above mid price (spread to prevent matching)
    reference_pool.place_limit_order<USDC, DEEP>(
        &mut balance_manager,
        &trade_proof,
        2,
        constants::no_restriction(),
        constants::self_matching_allowed(),
        11_000_000, // 0.011 * 1e9 (ask above)
        100 * test_constants::deep_multiplier(),
        false, // is_bid
        true, // pay_with_deep
        constants::max_u64(),
        clock,
        scenario.ctx(),
    );

    transfer::public_transfer(balance_manager, test_constants::user2());
    return_shared(reference_pool);

    // Add deep price point to target pool
    scenario.next_tx(test_constants::admin());
    let mut target_pool = scenario.take_shared_by_id<Pool<BaseAsset, QuoteAsset>>(target_pool_id);
    let reference_pool = scenario.take_shared_by_id<Pool<USDC, DEEP>>(reference_pool_id);

    pool::add_deep_price_point<BaseAsset, QuoteAsset, USDC, DEEP>(
        &mut target_pool,
        &reference_pool,
        clock,
    );

    return_shared(target_pool);
    return_shared(reference_pool);

    reference_pool_id
}

// === V2 trading wrappers ===
//
// The v2 entries on `pool_proxy` and `margin_manager` take additional
// margin-pool and oracle parameters so they can enforce a post-trade
// `risk_ratio` invariant. These wrappers fold the oracle build/destroy
// dance into one call. Callers pass already-shared margin pool refs
// (most tests already have them taken for borrow/withdraw setup).
//
// Signature shape: `(&mut scenario, &registry, &base_margin_pool,
// &quote_margin_pool, &mut mm, &mut pool, /* original v1 trade args */,
// &clock)`. The wrapper builds Pyth oracle objects for both assets,
// invokes the v2 entry with `scenario.ctx()`, and destroys the oracles.

public fun place_limit_order_v2_for_test<BaseAsset, QuoteAsset>(
    scenario: &mut Scenario,
    registry: &MarginRegistry,
    base_margin_pool: &MarginPool<BaseAsset>,
    quote_margin_pool: &MarginPool<QuoteAsset>,
    mm: &mut deepbook_margin::margin_manager::MarginManager<BaseAsset, QuoteAsset>,
    pool: &mut Pool<BaseAsset, QuoteAsset>,
    client_order_id: u64,
    order_type: u8,
    self_matching_option: u8,
    price: u64,
    quantity: u64,
    is_bid: bool,
    pay_with_deep: bool,
    expire_timestamp: u64,
    clock: &Clock,
): deepbook::order_info::OrderInfo {
    let base_oracle = build_price_info_for_type<BaseAsset>(scenario, clock);
    let quote_oracle = build_price_info_for_type<QuoteAsset>(scenario, clock);
    let order_info = pool_proxy::place_limit_order_v2<BaseAsset, QuoteAsset>(
        registry,
        mm,
        pool,
        base_margin_pool,
        quote_margin_pool,
        &base_oracle,
        &quote_oracle,
        client_order_id,
        order_type,
        self_matching_option,
        price,
        quantity,
        is_bid,
        pay_with_deep,
        expire_timestamp,
        clock,
        scenario.ctx(),
    );
    destroy(base_oracle);
    destroy(quote_oracle);
    order_info
}

