        assert!(order.balance_manager_id() == balance_manager_id_alice, 0);
        assert!(order.quantity() == 1 * constants::float_scaling(), 0);
        assert!(order.filled_quantity() == 0, 0);
        assert!(order.fee_is_deep() == true, 0);
