        // Should return (0, 0, 0) since we can't meet the target
        assert!(base_out_exceed == 0, 9);
        assert!(quote_in_exceed == 0, 10);
        assert!(deep_exceed == 0, 11);

        // Test 5: Small target (5 SUI)
