        registry_id,
        balance_manager_id_alice,
        &mut test,
    );

    let price = 2 * constants::float_scaling();
    let quantity = 10 * constants::float_scaling();
    let expire_timestamp = constants::max_u64();
    let pay_with_deep = true;

    // Place a maker order on the opposite side
    // If we're swapping base to quote, we need a bid order to match against
    // If we're swapping quote to base, we need an ask order to match against
    place_limit_order<SUI, USDC>(
        ALICE,
        pool_id,
        balance_manager_id_alice,
        1,
        constants::no_restriction(),
        constants::self_matching_allowed(),
        price,
        quantity,
        is_base_to_quote,
        pay_with_deep,
        expire_timestamp,
        &mut test,
    );

    // Create Bob's balance manager with caps
    let bob_balance_manager_id = create_acct_only_deep_and_share_with_funds(
        BOB,
        1000000 * constants::float_scaling(),
        &mut test,
    );
    create_caps(BOB, bob_balance_manager_id, &mut test);

    // Use an exact lot-size multiple so there's no leftover
    let swap_quantity = 5 * constants::float_scaling();

    if (is_base_to_quote) {
        // Swap exactly 5 SUI for USDC - should result in base_out = 0
        let (base_out, quote_out) = place_exact_base_for_quote_with_manager<SUI, USDC>(
            pool_id,
            BOB,
            bob_balance_manager_id,
            swap_quantity,
            0,
            &mut test,
        );

        // base_out should be 0 (all base was swapped)
        assert!(base_out.value() == 0);
        // quote_out should be swap_quantity * price = 5 * 2 = 10 USDC
        assert!(quote_out.value() == math::mul(swap_quantity, price));

        base_out.burn_for_testing();
        quote_out.burn_for_testing();
    } else {
        // Swap exactly 10 USDC for SUI - should result in quote_out = 0
        let quote_swap_quantity = 10 * constants::float_scaling();
        let (base_out, quote_out) = place_exact_quote_for_base_with_manager<SUI, USDC>(
            pool_id,
            BOB,
            bob_balance_manager_id,
            quote_swap_quantity,
            0,
            &mut test,
        );

        // quote_out should be 0 (all quote was swapped)
        assert!(quote_out.value() == 0);
        // base_out should be quote_swap_quantity / price = 10 / 2 = 5 SUI
        assert!(base_out.value() == math::div(quote_swap_quantity, price));

        base_out.burn_for_testing();
        quote_out.burn_for_testing();
    };

    end(test);
}

/// Verifies that get_quantity_out rejects ask (sell) orders where the executed
/// base quantity is below min_size, matching the existing behavior for bids.
/// Scenario: A bid rests with only lot_size remaining after partial fill.
/// A sell simulation should be rejected since it can only fill lot_size < min_size.
fun test_get_quantity_out_ask_min_size_enforced() {
    let mut test = begin(OWNER);
    let registry_id = setup_test(OWNER, &mut test);
    let balance_manager_id_alice = create_acct_and_share_with_funds(
        ALICE,
        1000000 * constants::float_scaling(),
        &mut test,
    );
    let pool_id = setup_pool_with_default_fees_and_reference_pool<SUI, USDC, SUI, DEEP>(
        ALICE,
        registry_id,
        balance_manager_id_alice,
        &mut test,
    );

    let price = 2 * constants::float_scaling();
    let expire_timestamp = constants::max_u64();
    let pay_with_deep = true;

    // Place a bid for min_size + lot_size (11000)
    place_limit_order<SUI, USDC>(
        ALICE,
        pool_id,
        balance_manager_id_alice,
        1,
        constants::no_restriction(),
        constants::self_matching_allowed(),
        price,
        constants::min_size() + constants::lot_size(),
        true,
        pay_with_deep,
        expire_timestamp,
        &mut test,
    );

    // Partially fill the bid by selling min_size (10000), leaving only lot_size (1000) remaining
    place_limit_order<SUI, USDC>(
        ALICE,
        pool_id,
        balance_manager_id_alice,
        2,
        constants::no_restriction(),
        constants::self_matching_allowed(),
        price,
        constants::min_size(),
        false,
        pay_with_deep,
        expire_timestamp,
        &mut test,
    );

    // Now only lot_size (1000) of the bid remains, which is < min_size (10000).
    // Selling a large quantity should be rejected because the executed base
    // would only be lot_size, which is below min_size.
    let sell_quantity = 10 * constants::min_size();
    let (base_out, quote_out, deep_required) = get_quote_quantity_out<SUI, USDC>(
        pool_id,
        sell_quantity,
        &mut test,
    );

    // With the fix, get_quantity_out should reject the dust fill and return
    // the original sell_quantity as base_out (unchanged) with 0 quote and 0 deep.
    assert_eq!(base_out, sell_quantity);
    assert_eq!(quote_out, 0);
    assert_eq!(deep_required, 0);

    end(test);
}

