        &mut test,
    );

    // Alice posts two bids at different prices. Bob will fill only the higher one.
    let to_be_filled = place_limit_order<SUI, USDC>(
        ALICE,
        pool_id,
        balance_manager_id_alice,
        1,
        constants::no_restriction(),
