        constants::self_matching_allowed(),
        1 * constants::float_scaling(),
        1 * constants::float_scaling(),
        true,
        true,
        constants::max_u64(),
        &mut test,
    );
    let filled_id = to_be_filled.order_id();
    let live_id = to_stay_live.order_id();

