```move
module deepbook::market_order {
    use sui::tx_context::TxContext;
    use sui::coin::{Self, Coin};
    use sui::balance::{Self, Balance};
    use sui::sui::SUI;
    use sui::clock::Clock;
    use deepbook::order::{Self, Order, OrderType};
    use deepbook::trade_proof::{Self, TradeProof};
    use deepbook::pool::{Self, Pool};
    use deepbook::balance_manager::{Self, BalanceManager};
    use deepbook::custodian::{Self, Custodian};
    use deepbook::math;
    use deepbook::constants;

    public fun execute_market_order(
        pool: &mut Pool,
        balance_manager: &mut BalanceManager,
        custodian: &mut Custodian,
        base_coin: Coin<SUI>,
        quote_coin: Coin<SUI>,
        is_buy: bool,
        quantity: u64,
        clock: &Clock,
        ctx: &mut TxContext
    ): (TradeProof, Coin<SUI>, Coin<SUI>) {
        let (base_balance, quote_balance) = if (is_buy) {
            let base_balance = balance_manager.withdraw_base(&mut base_coin, quantity, ctx);
            let quote_balance = balance::zero<SUI>();
            (base_balance, quote_balance)
        } else {
            let base_balance = balance::zero<SUI>();
            let quote_balance = balance_manager.withdraw_quote(&mut quote_coin, quantity, ctx);
            (base_balance, quote_balance)
        };

        let order = order::new_market_order(
            is_buy,
            quantity,
            clock,
            ctx
        );

        let (trade_proof, remaining_base, remaining_quote) = pool.execute_order(
            order,
            base_balance,
            quote_balance,
            custodian,
            clock,
            ctx
        );

        let base_coin = if (is_buy) {
            coin::from_balance(remaining_base, ctx)
        } else {
            coin::join(&mut base_coin, coin::from_balance(remaining_base, ctx))
        };

        let quote_coin = if (is_buy) {
            coin::join(&mut quote_coin, coin::from_balance(remaining_quote, ctx))
        } else {
            coin::from_balance(remaining_quote, ctx)
        };

        (trade_proof, base_coin, quote_coin)
    }

    #[test_only]
    public fun test_execute_market_order(
        pool: &mut Pool,
        balance_manager: &mut BalanceManager,
        custodian: &mut Custodian,
        base_coin: Coin<SUI>,
        quote_coin: Coin<SUI>,
        is_buy: bool,
        quantity: u64,
        clock: &Clock,
        ctx: &mut TxContext
    ): TradeProof {
        let (trade_proof, base_coin, quote_coin) = execute_market_order(
            pool,
            balance_manager,
            custodian,
            base_coin,
            quote_coin,
            is_buy,
            quantity,
            clock,
            ctx
        );

        coin::destroy_zero(base_coin);
        coin::destroy_zero(quote_coin);

        trade_proof
    }
}
