module flash::flash_loan {
    use sui::tx_context::TxContext;
    use sui::coin::{Self, Coin};
    use sui::balance::{Self, Balance};
    use sui::transfer;
    use sui::object::{Self, UID};
    use deepbook::deepbook::{Self, DEEP};
    use deepbook::custodian_v2::{Self, CustodianV2};
    use deepbook::flash_loan::{Self, FlashLoanReceipt};

    public struct FlashLoan<phantom T> has key, store {
        id: UID,
        amount: u64,
        coin: Coin<T>
    }

    public fun borrow_flash_loan<T>(
        custodian: &mut CustodianV2<T>,
        amount: u64,
        ctx: &mut TxContext
    ): (Coin<T>, FlashLoanReceipt<T>) {
        let (coin, receipt) = deepbook::borrow_flash_loan(custodian, amount, ctx);
        (coin, FlashLoanReceipt {
            id: object::new(ctx),
            amount,
            coin
        })
    }

    public fun repay_flash_loan<T>(
        custodian: &mut CustodianV2<T>,
        coin: Coin<T>,
        receipt: FlashLoanReceipt<T>
    ) {
        let FlashLoanReceipt { id, amount, coin } = receipt;
        object::delete(id);
        deepbook::repay_flash_loan(custodian, coin, amount);
    }

