    public struct FlashLoan<phantom T> has key {
        id: ID,
        amount: u64,
        vault_id: ID,
    }

    /// Borrow DEEP tokens from a pool and require repayment before the end of the transaction
    public fun borrow_flash_loan(
        pool: &mut Pool<DEEP>,
        amount: u64,
        ctx: &mut TxContext
    ): FlashLoan<DEEP> {
        let vault_id = pool::get_custodian_vault_id(pool);
        let vault = custodian_vault::borrow_mut(vault_id);
        let coins = custodian_vault::withdraw(vault, amount, ctx);

        FlashLoan {
            id: object::new(ctx),
            amount,
            vault_id,
        }
    }

    /// Repay the flash loan with the borrowed amount plus fee
    public fun repay_flash_loan(
        loan: FlashLoan<DEEP>,
        payment: Coin<DEEP>,
        ctx: &mut TxContext
    ) {
        let FlashLoan { id, amount, vault_id } = loan;
        let payment_balance = coin::into_balance(payment);
        assert!(balance::value(&payment_balance) >= amount, EFlashLoanNotRepaid);

        let vault = custodian_vault::borrow_mut(vault_id);
        custodian_vault::deposit(vault, payment_balance);
        object::delete(id);
    }

