module deepbook::limit_order {
    use sui::balance_manager::BalanceManager;
    use sui::tx_context::TxContext;
    use sui::object::{ID, UID};
    use sui::transfer;
    use sui::coin::Coin;
    use sui::sui::SUI;
    use deepbook::pool::Pool;
    use deepbook::order::{Order, OrderSide, OrderType};
    use deepbook::events::OrderPlaced;

    public fun place_limit_order<BaseType, QuoteType>(
        pool: &mut Pool<BaseType, QuoteType>,
        balance_manager: &mut BalanceManager,
        price: u64,
        quantity: u64,
        is_bid: bool,
        expiration_timestamp: u64,
        clock: &Clock,
        ctx: &mut TxContext
    ) {
        let order_side = if is_bid { OrderSide::Bid } else { OrderSide::Ask };
        let order_type = OrderType::Limit;

        let (base_coin, quote_coin) = if is_bid {
            let quote_coin = balance_manager.withdraw<QuoteType>(ctx, price * quantity);
            (balance_manager.zero<BaseType>(), quote_coin)
        } else {
            let base_coin = balance_manager.withdraw<BaseType>(ctx, quantity);
            (base_coin, balance_manager.zero<QuoteType>())
        };

        let order_id = pool.place_order(
            order_side,
            order_type,
            price,
            quantity,
            expiration_timestamp,
            base_coin,
            quote_coin,
            clock,
            ctx
        );

        event::emit(OrderPlaced {
            order_id,
            pool_id: pool.id(),
            price,
            quantity,
            side: order_side,
            order_type,
            expiration_timestamp,
            sender: tx_context::sender(ctx),
        });
    }
}
