module deepbook_example::limit_order {
    use sui::balance::{Self, Balance};
    use sui::coin::{Self, Coin};
    use sui::tx_context::TxContext;
    use deepbook::balance_manager::{Self, BalanceManager};
    use deepbook::custodian_v2::{Self, CustodianV2};
    use deepbook::order::{Self, Order, OrderType};
    use deepbook::pool::{Self, Pool};
    use deepbook::types::{Price, Quantity};

    public fun place_limit_order<BaseType, QuoteType>(
        pool: &mut Pool<BaseType, QuoteType>,
        custodian: &mut CustodianV2<BaseType, QuoteType>,
        balance_manager: &mut BalanceManager<BaseType, QuoteType>,
        base_coin: Coin<BaseType>,
        quote_coin: Coin<QuoteType>,
        price: Price,
        quantity: Quantity,
        is_bid: bool,
        ctx: &mut TxContext
    ) {
        let base_balance = balance::increase_balance(balance::zero(), base_coin);
        let quote_balance = balance::increase_balance(balance::zero(), quote_coin);

        let (base_balance, quote_balance) = custodian_v2::deposit(
            custodian,
            base_balance,
            quote_balance,
            ctx
        );

        let order_type = if (is_bid) {
            order::bid()
        } else {
            order::ask()
        };

        let order = order::new_limit_order(
            price,
            quantity,
            order_type,
            ctx
        );

        balance_manager::place_order(
            balance_manager,
            pool,
            order,
            base_balance,
            quote_balance,
            ctx
        );
    }

    #[test_only]
    public fun test_place_limit_order<BaseType, QuoteType>(
        pool: &mut Pool<BaseType, QuoteType>,
        custodian: &mut CustodianV2<BaseType, QuoteType>,
