        quote_coin: Coin<QuoteType>,
        price: u64,
        quantity: u64,
        is_bid: bool,
        ctx: &mut TxContext
    ) {
        place_limit_order(
            pool,
            custodian,
            balance_manager,
            base_coin,
            quote_coin,
            price,
            quantity,
            is_bid,
            ctx
        );
    }
}
