module deepbook::flash_loan {
    use sui::tx_context::TxContext;
    use sui::coin::{Coin, Self};
    use sui::balance::{Self, Balance};
    use deepbook::pool::{Self, Pool};
    use deepbook::math;
    use deepbook::custodian::{Self, Custodian};
    use deepbook::types::{DEEP};

    /// Error codes
    const EFlashLoanNotRepaid: u64 = 0;
    const EInsufficientAmount: u64 = 1;

    /// Flash loan event
    struct FlashLoanEvent has copy, drop {
        amount: u64,
        repaid: bool
    }

    /// Perform a flash loan of DEEP tokens
    public entry fun flash_loan(
        pool: &mut Pool,
        custodian: &mut Custodian,
        amount: u64,
        callback: vector<u8>,
        ctx: &mut TxContext
    ) {
        assert!(amount > 0, EInsufficientAmount);

        // Borrow DEEP tokens from the pool
        let deep_coin = pool.borrow(amount, ctx);

        // Execute callback with the borrowed coins
        let callback_success = sui::programmable_transactions::execute(
            callback,
            vector[deep_coin],
            ctx
        );

        // Verify the loan was repaid
        let repaid = balance::value(&custodian.balance<DEEP>()) >= amount;
        assert!(repaid, EFlashLoanNotRepaid);

        // Emit event
        event::emit(FlashLoanEvent {
            amount,
            repaid
        });
    }

    /// Repay a flash loan
    public fun repay_flash_loan(
        custodian: &mut Custodian,
        coin: Coin<DEEP>,
    ) {
        custodian.deposit(coin);
    }
}

