#[test]
#[expected_failure(abort_code = sui::object_table::ETableNotEmpty)]
fun destroy_non_empty() {
    let sender = @0x0;
    let mut scenario = test_scenario::begin(sender);
    let mut table = object_table::new(scenario.ctx());
