module deepbook::market_order {
    use sui::tx_context::TxContext;
    use sui::object::{ID, UID};
    use sui::transfer;
    use sui::coin::{Coin, Self};
    use sui::balance::{Self, Balance};
    use deepbook::order_book::{Self, OrderBook};
    use deepbook::trade_proof::{Self, TradeProof};
    use deepbook::custodian::{Self, Custodian};
    use deepbook::utils;
    use deepbook::math;
    use deepbook::constants;

    /// Executes a market order on DeepBook
    public fun execute_market_order<BaseAsset, QuoteAsset>(
        order_book: &mut OrderBook<BaseAsset, QuoteAsset>,
        custodian: &mut Custodian<BaseAsset, QuoteAsset>,
        base_coins: vector<Coin<BaseAsset>>,
        quote_coins: vector<Coin<QuoteAsset>>,
        is_buy: bool,
        quantity: u64,
        ctx: &mut TxContext
    ): (TradeProof, Balance<BaseAsset>, Balance<QuoteAsset>) {
        let (base_balance, quote_balance) = if (is_buy) {
            let quote_balance = balance::join_all(quote_coins);
            (balance::zero<BaseAsset>(), quote_balance)
        } else {
            let base_balance = balance::join_all(base_coins);
            (base_balance, balance::zero<QuoteAsset>())
        };

        let (trade_proof, base_balance, quote_balance) = order_book::execute_market_order(
            order_book,
            custodian,
            base_balance,
            quote_balance,
            is_buy,
            quantity,
            ctx
        );

        (trade_proof, base_balance, quote_balance)
    }

    /// Creates a new TradeProof for order execution
    public fun create_trade_proof<BaseAsset, QuoteAsset>(
        order_book_id: ID,
        custodian_id: ID,
        base_amount: u64,
        quote_amount: u64,
        is_buy: bool,
        ctx: &mut TxContext
    ): TradeProof {
        trade_proof::new(
            order_book_id,
            custodian_id,
            base_amount,
            quote_amount,
            is_buy,
            ctx
        )
    }

    /// Wrapper function that combines creating a TradeProof and executing a market order
    public entry fun market_order<BaseAsset, QuoteAsset>(
        order_book: &mut OrderBook<BaseAsset, QuoteAsset>,
        custodian: &mut Custodian<BaseAsset, QuoteAsset>,
        base_coins: vector<Coin<BaseAsset>>,
        quote_coins: vector<Coin<QuoteAsset>>,
        is_buy: bool,
        quantity: u64,
        ctx: &mut TxContext
    ) {
        let (trade_proof, base_balance, quote_balance) = execute_market_order(
            order_book,
            custodian,
            base_coins,
            quote_coins,
            is_buy,
            quantity,
            ctx
        );

        // Return coins to sender
        if (!balance::is_zero(&base_balance)) {
            let base_coin = coin::from_balance(base_balance, ctx);
            transfer::public_transfer(base_coin, ctx.sender());
        };
        if (!balance::is_zero(&quote_balance)) {
            let quote_coin = coin::from_balance(quote_balance, ctx);
            transfer::public_transfer(quote_coin, ctx.sender());
        };

        // Transfer trade proof to sender
        transfer::public_transfer(trade_proof, ctx.sender());
    }
}
