    public fun execute_market_order(
        registry: &mut Registry,
        pool: &mut Pool,
        base_coin: Coin<SUI>,
        quote_coin: Coin<SUI>,
        side: OrderSide,
        quantity: u64,
        price: u64,
        custodian_vault: &mut CustodianVault,
        ctx: &mut TxContext
