            registry,
            order,
            base_balance,
            quote_balance,
            custodian_vault,
            ctx
        );

        (trade_proof, base_balance_out, quote_balance_out)
    }

    public fun create_trade_proof(
        registry: &mut Registry,
        pool: &mut Pool,
