module deepbook::limit_order {
    use sui::balance::{Self, Balance};
    use sui::coin::{Self, Coin};
    use sui::tx_context::TxContext;
    use deepbook::math;
    use deepbook::pool::{Self, Pool};
    use deepbook::balance_manager::{Self, BalanceManager};
    use deepbook::order::{Self, Order, OrderSide};
    use deepbook::price_level::{Self, PriceLevel};

    /// Places a limit order on a DeepBook v3 pool using a BalanceManager.
    /// Returns the order ID.
    public fun place_limit_order<BaseType, QuoteType>(
        pool: &mut Pool<BaseType, QuoteType>,
        balance_manager: &mut BalanceManager<BaseType, QuoteType>,
        base_coin: Coin<BaseType>,
        quote_coin: Coin<QuoteType>,
        price: u64,
        quantity: u64,
        is_bid: bool,
        ctx: &mut TxContext
    ): u64 {
        let base_balance = balance_manager.deposit_base(base_coin);
        let quote_balance = balance_manager.deposit_quote(quote_coin);

        let side = if (is_bid) OrderSide::Bid else OrderSide::Ask;
        let order = order::new(
            balance::value(&base_balance),
            balance::value(&quote_balance),
            price,
            quantity,
            side,
            ctx
        );

        let order_id = order::id(&order);
        balance_manager.add_order(order);

        let price_level = price_level::new(price);
        pool.place_limit_order(balance_manager, price_level, order_id, is_bid);

        order_id
    }
}
