    assert!(prices[0] == 170 * constants::float_scaling(), EIncorrectLevel2Price);
    assert!(quantities[0] == 5 * constants::float_scaling(), EIncorrectLevel2Quantity);

    // Only the best bid of 30 and best ask of 170 should be returned
