// === liquidation priority ordering ===

#[test]
fun higher_leverage_order_id_sorts_first() {
    let high = order::new_from_boundary_indices(
        OPENED_AT_MS,
        0,
        BOUNDARY_INDEX_HI,
        order::leverage_three_x(),
        500_000_000,
        ONE_LOT_QTY,
        0,
    );
    let low = order::new_from_boundary_indices(
        OPENED_AT_MS,
        0,
        BOUNDARY_INDEX_HI,
        order::leverage_two_x(),
        500_000_000,
        ONE_LOT_QTY,
        0,
    );

    assert!(high.id() < low.id());
}

#[test]
fun larger_quantity_order_id_sorts_first_before_leverage() {
    let large = order::new_from_boundary_indices(
        OPENED_AT_MS,
        0,
        BOUNDARY_INDEX_HI,
        order::leverage_two_x(),
        500_000_000,
        TWO_LOTS_QTY,
        0,
    );
    let small = order::new_from_boundary_indices(
        OPENED_AT_MS,
        0,
        BOUNDARY_INDEX_HI,
        order::leverage_three_x(),
        500_000_000,
        ONE_LOT_QTY,
        0,
    );

    assert!(large.id() < small.id());
}

#[test]
fun lower_open_side_sorts_before_higher_open_side_when_other_priority_matches() {
    let lower_open = order::new_from_boundary_indices(
        OPENED_AT_MS,
        0,
        BOUNDARY_INDEX_HI,
        order::leverage_two_x(),
        500_000_000,
        ONE_LOT_QTY,
        0,
    );
    let higher_open = order::new_from_boundary_indices(
        OPENED_AT_MS,
        BOUNDARY_INDEX_LO,
        max_boundary_index(),
        order::leverage_two_x(),
        500_000_000,
        ONE_LOT_QTY,
        0,
    );

    assert!(lower_open.id() < higher_open.id());
}

// === replacement ===

#[test]
fun replacement_inherits_terms_and_uses_new_sequence() {
    let original = order::new_from_boundary_indices(
        OPENED_AT_MS,
        BOUNDARY_INDEX_LO,
        BOUNDARY_INDEX_HI,
        order::leverage_one_x(),
        500_000_000,
        TWO_LOTS_QTY,
        0,
    );
    let next_sequence = 1u64;
    let replaced = original.replacement(ONE_LOT_QTY, next_sequence);

    // Inherits the original strike range, leverage, entry probability, and open
    // time; only quantity and sequence change.
    assert_eq!(replaced.opened_at_ms(), original.opened_at_ms());
    assert_eq!(replaced.lower_boundary_index(), original.lower_boundary_index());
    assert_eq!(replaced.higher_boundary_index(), original.higher_boundary_index());
    assert_eq!(replaced.leverage(), original.leverage());
    assert_eq!(replaced.entry_probability(), original.entry_probability());
    assert_eq!(replaced.quantity(), ONE_LOT_QTY);
    assert_eq!(replaced.sequence(), next_sequence);
}

#[test, expected_failure(abort_code = order::EInvalidQuantity)]
fun replacement_at_or_above_original_quantity_aborts() {
    // Replacement quantity must be strictly less than original.
    let original = order::new_from_boundary_indices(
        OPENED_AT_MS,
        BOUNDARY_INDEX_LO,
        BOUNDARY_INDEX_HI,
        order::leverage_one_x(),
        0,
        ONE_LOT_QTY,
        0,
    );
    let _ = original.replacement(ONE_LOT_QTY, 1u64);
    abort 999
}

