module deepbook_trader::market_order {
    use sui::tx_context::TxContext;
    use sui::object::{ID, UID};
    use sui::transfer;
    use sui::coin::{Coin, TreasuryCap};
    use sui::balance::{Balance, Supply};
    use deepbook::custodian_v2::{Self, CustodianV2};
    use deepbook::order::{Self, Order, OrderType};
    use deepbook::pool::{Self, Pool};
    use deepbook::utils;
    use deepbook::critbit::{Self, CritbitTree};
    use deepbook::types::{Self, Side, IOC};
    use deepbook::trade_proof::{Self, TradeProof};

    public fun execute_market_order<BaseType, QuoteType>(
        pool: &mut Pool<BaseType, QuoteType>,
        custodian: &mut CustodianV2<BaseType, QuoteType>,
        quantity: u64,
        side: Side,
        base_coin: Coin<BaseType>,
        quote_coin: Coin<QuoteType>,
        ctx: &mut TxContext
    ): (TradeProof, Coin<BaseType>, Coin<QuoteType>) {
        let (trade_proof, base_coin, quote_coin) = if (side == Side::Ask) {
            let (trade_proof, base_coin, quote_coin) = pool::market_order<BaseType, QuoteType>(
                pool,
                custodian,
                quantity,
                side,
                OrderType::ImmediateOrCancel(IOC {}),
                base_coin,
                quote_coin,
                ctx
            );
            (trade_proof, base_coin, quote_coin)
        } else {
            let (trade_proof, base_coin, quote_coin) = pool::market_order<BaseType, QuoteType>(
                pool,
