module deepbook_example::limit_order {
    use sui::balance::{Self, Balance};
    use sui::coin::{Self, Coin};
    use sui::tx_context::{Self, TxContext};
    use deepbook::balance_manager::{Self, BalanceManager};
    use deepbook::custodian::{Self, Custodian};
    use deepbook::order::{Self, Order, OrderSide};
    use deepbook::pool::{Self, Pool};
    use deepbook::types::{Price, Quantity};

    public fun place_limit_order<BaseType, QuoteType>(
        balance_manager: &mut BalanceManager,
        custodian: &mut Custodian,
        pool: &mut Pool<BaseType, QuoteType>,
        base_coin: Coin<BaseType>,
        quote_coin: Coin<QuoteType>,
        price: Price,
        quantity: Quantity,
        is_bid: bool,
        ctx: &mut TxContext
    ) {
        let base_balance = balance::increase_balance(&mut custodian.base_balance, base_coin);
        let quote_balance = balance::increase_balance(&mut custodian.quote_balance, quote_coin);

        let order_side = if (is_bid) {
            OrderSide::Bid
        } else {
            OrderSide::Ask
        };

        let order = order::new_limit_order(
            price,
            quantity,
            order_side,
            ctx
        );

        balance_manager::deposit(balance_manager, base_balance, quote_balance);
        pool::place_limit_order(pool, order, ctx);
    }

    #[test]
    fun test_place_limit_order() {
        let ctx = &mut tx_context::dummy();

        // Setup test environment
        let balance_manager = balance_manager::new(ctx);
        let custodian = custodian::new(ctx);
        let pool = pool::new<Coin<BaseType>, Coin<QuoteType>>(ctx);

        // Create test coins
        let base_coin = coin::mint<BaseType>(100, ctx);
        let quote_coin = coin::mint<QuoteType>(1000, ctx);

        // Place limit order
        place_limit_order(
            &mut balance_manager,
            &mut custodian,
            &mut pool,
            base_coin,
            quote_coin,
            100, // price
            10,  // quantity
            true, // is_bid
            ctx
        );
    }
}
